import{_ as t,o as i,c as a,a1 as o}from"./chunks/framework.BX4nIuL2.js";const b=JSON.parse('{"title":"Image upload service","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/1projectmanage/imageuploadservice.md","filePath":"courses/fab-course/doc/1projectmanage/imageuploadservice.md"}'),r={name:"courses/fab-course/doc/1projectmanage/imageuploadservice.md"};function l(c,e,n,p,g,s){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="image-upload-service" tabindex="-1">Image upload service <a class="header-anchor" href="#image-upload-service" aria-label="Permalink to &quot;Image upload service&quot;">​</a></h1><h2 id="picgo-gitlab" tabindex="-1">picgo+gitlab <a class="header-anchor" href="#picgo-gitlab" aria-label="Permalink to &quot;picgo+gitlab&quot;">​</a></h2><p>The function of Image upload service is to storage your picture or video on cloud and then you can use the link in your markdown document.Then Image upload service will export one link for your information(it would used in markdown document).The following show one method using <a href="https://github.com/Molunerfinn/PicGo" target="_blank" rel="noreferrer">PicGo</a> and gitlab to build.</p><ol><li>Download <a href="https://github.com/Molunerfinn/PicGo/releases" target="_blank" rel="noreferrer">PicGo application from github</a> and install it.</li><li>Open PicGo and setting the software.Now we need open gitlab to get some information(obvious we have some other choice to storage our information ,for example Github ,Aliyun OSS ,Imgur,etc),</li></ol><ul><li><p>url: gitlab url (eg:<a href="https://gitlab.com" target="_blank" rel="noreferrer">https://gitlab.com</a>)</p></li><li><p>group: gitlab project&#39;s group name</p></li><li><p>project: gitlab project name</p></li><li><p>token: gitlab&#39;s api token (Setting /Access Token/Click )</p><p><img src="https://gitlab.com/picbed/bed/uploads/f52be9d7e151da2311ca5065966fdbf9/picturebed.png" alt=""><img src="https://gitlab.com/picbed/bed/uploads/1a26b21c03c177d2241a6595ba38cd66/picgoinfor.png" alt=""></p></li></ul><ol start="3"><li>OK ,update picture to gitlab</li></ol><ul><li>method1: right click and choice update picture with picgo</li><li>method2:push picture to picgo <img src="https://gitlab.com/picbed/bed/uploads/93c7be671e3913b6913a2c17a0e4c054/rightbotton.png" alt=""><img src="https://gitlab.com/picbed/bed/uploads/2a172fda6f4924325d05a598594e0c1e/method2.png" alt=""></li></ul><ol start="4"><li>Click the picture you want and get the link <img src="https://gitlab.com/picbed/bed/uploads/103e19a8b5ce9f1b97636497391e1c34/picgoclick.png" alt=""></li></ol><h2 id="picgo-github" tabindex="-1">picgo+github <a class="header-anchor" href="#picgo-github" aria-label="Permalink to &quot;picgo+github&quot;">​</a></h2><ol><li><p>Create and log in your GitHub account.</p></li><li><p>Create a repo for GitHub Img.</p><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/202210072254543.png" alt=""><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/202210072254544.png" alt=""></p></li><li><p>Generate a token for PicGo:</p></li></ol><p>Access: <a href="https://github.com/setting/tokens" target="_blank" rel="noreferrer">https://github.com/setting/tokens</a></p><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/202210072254542.png" alt=""></p><p><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/202210072254545.png" alt=""><img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/202210072258995.png" alt=""> 4. Configure your GitHub repository for PicGo. <img src="https://raw.githubusercontent.com/bobwu0214/imageuploadservice/main/img/202210072259478.png" alt=""><a href="https://cdn.jsdelivr.net/gh/zimaStrawer/doubleQ_Image/picgo_peizhi.png" target="_blank" rel="noreferrer">Also you can write the following to speed up the loading&quot;https://cdn.jsdelivr.net/gh/username/repostory&quot;</a></p><h2 id="reference" tabindex="-1">reference: <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;reference:&quot;">​</a></h2><ul><li><a href="https://github.com/Molunerfinn/PicGo/releases" target="_blank" rel="noreferrer">Picgo github</a></li><li><a href="https://github.com/bugwz/picgo-plugin-gitlab" target="_blank" rel="noreferrer">Picgo gitlab</a></li><li><a href="https://github.com/Molunerfinn/PicGo/releases" target="_blank" rel="noreferrer">Picgo+github</a></li><li><a href="https://nexmaker-fab.github.io/2022zjude1-doubleQ/#/Course_practice/Web/" target="_blank" rel="noreferrer">Cdn picgo from zju2022 doubleQ</a></li></ul>',15)])])}const h=t(r,[["render",l]]);export{b as __pageData,h as default};
